  `sala_idsala` INT UNSIGNED NULL,
  PRIMARY KEY (`idvol_local`),
  UNIQUE INDEX `idvol_local_UNIQUE` (`idvol_local` ASC),
  INDEX `fk_vol_local_local1_idx` (`local_idlocal` ASC),
  INDEX `fk_vol_local_voluntario1_idx` (`voluntario_idvoluntario` ASC),
  INDEX `fk_vol_local_sala1_idx` (`sala_idsala` ASC),
  CONSTRAINT `fk_vol_local_local1`
    FOREIGN KEY (`local_idlocal`)
    REFERENCES `Cajuru`.`local` (`idlocal`)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION,
  CONSTRAINT `fk_vol_local_voluntario1`
    FOREIGN KEY (`voluntario_idvoluntario`)
    REFERENCES `Cajuru`.`voluntario` (`idvoluntario`)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION,
  CONSTRAINT `fk_vol_local_sala1`
    FOREIGN KEY (`sala_idsala`)
    REFERENCES `Cajuru`.`sala` (`idsala`)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION)
ENGINE = InnoDB;


