SET UNIQUE_CHECKS=@OLD_UNIQUE_CHECKS;










DELIMITER $$

CREATE TRIGGER trg_vol_atividades_after_insert
AFTER INSERT ON vol_atividades
FOR EACH ROW
BEGIN
    INSERT INTO reg_atividades (
        idmetrica_atividade,
        data_referencia,
        quantidade,
        vol_atividades_idvol_atividades
    )
    VALUES (
        NEW.idmetrica_atividade,
        DATE(NEW.data_hora), -- Extrai apenas a parte da data do TIMESTAMP
        1,                   -- Cada registro automático conta como 1
        NEW.idvol_atividades -- Mantém o link com a origem
    );
END$$

DELIMITER ;



DELIMITER $$

CREATE TRIGGER trg_reg_manual_after_insert
AFTER INSERT ON reg_manual
FOR EACH ROW
BEGIN
    INSERT INTO reg_atividades (
        idmetrica_atividade,
        data_referencia,
        quantidade,
        reg_manual_idreg_manual
    )
    VALUES (
        NEW.idmetrica_atividade,
        NEW.data,
        NEW.quantidade,
        NEW.idreg_manual -- Mantém o link com a origem
    );
END$$

DELIMITER ;


CREATE VIEW vw_indicadores_voluntariado AS
SELECT
    RA.data_referencia AS data,
    A.nome AS atividade,
    M.nome AS metrica,
    RA.quantidade
FROM
    reg_atividades RA
    INNER JOIN metrica_atividade MA ON RA.idmetrica_atividade = MA.idmetrica_atividade
    INNER JOIN atividade A ON MA.atividade_idatividade = A.idatividade
    INNER JOIN metrica M ON MA.metrica_idmetrica = M.idmetrica;
    
    


CREATE OR REPLACE VIEW vw_lista_presenca AS
SELECT 
    p.idpresenca,
    v.codigo_cracha,
    v.nome AS nome_voluntario,
    vd.hospital,
    vd.atividade,
    DATE_FORMAT(p.hora_entrada, '%H:%i') AS horario_entrada,
    DATE_FORMAT(p.hora_saida, '%H:%i') AS horario_saida,
    p.status_presenca
FROM presenca p
INNER JOIN voluntariado vd ON p.idvoluntariado = vd.idvoluntariado
INNER JOIN voluntario v ON vd.voluntario_idvoluntario = v.idvoluntario
WHERE DATE(p.hora_entrada) = CURDATE();
    
    
    
CREATE OR REPLACE VIEW vw_frequencia_individual AS
SELECT 
    v.idvoluntario,
    v.nome,
    -- Total de registros (presenças + faltas registradas)
    COUNT(p.idpresenca) AS total_escalas_registradas,
    -- Conta 'presente' ou 'finalizado' como comparecimento
    SUM(CASE WHEN p.status_presenca IN ('presente', 'finalizado') THEN 1 ELSE 0 END) AS total_presencas,
    -- Conta 'falta' apenas se você registrar explicitamente
    SUM(CASE WHEN p.status_presenca = 'falta' THEN 1 ELSE 0 END) AS total_faltas,
    -- Cálculo da porcentagem (evita divisão por zero)
    IF(COUNT(p.idpresenca) > 0, 
       ROUND((SUM(CASE WHEN p.status_presenca IN ('presente', 'finalizado') THEN 1 ELSE 0 END) / COUNT(p.idpresenca)) * 100, 1), 
       0) AS porcentagem_presenca
FROM voluntario v
LEFT JOIN voluntariado vd ON v.idvoluntario = vd.voluntario_idvoluntario
LEFT JOIN presenca p ON vd.idvoluntariado = p.idvoluntariado
GROUP BY v.idvoluntario, v.nome;



CREATE OR REPLACE VIEW vw_frequencia_geral AS
SELECT 
    COUNT(p.idpresenca) AS total_registros_instituicao,
    SUM(CASE WHEN p.status_presenca IN ('presente', 'finalizado') THEN 1 ELSE 0 END) AS total_presencas_geral,
    SUM(CASE WHEN p.status_presenca = 'falta' THEN 1 ELSE 0 END) AS total_faltas_geral,
    IF(COUNT(p.idpresenca) > 0, 
       ROUND((SUM(CASE WHEN p.status_presenca IN ('presente', 'finalizado') THEN 1 ELSE 0 END) / COUNT(p.idpresenca)) * 100, 1), 
       0) AS taxa_assiduidade_geral
FROM presenca p;


CREATE OR REPLACE VIEW vw_salas_livres_agora AS
SELECT 
    s.idsala,
    s.hospital,
    s.codigo_sala,
    s.nome_sala,
    s.capacidade,
    l.nome AS nome_local
FROM sala s
LEFT JOIN local l ON s.local_idlocal = l.idlocal
WHERE 
    -- Critério 1: NÃO pode estar em uma reserva ativa agora
    s.idsala NOT IN (
        SELECT sala_idsala 
        FROM reserva_sala rs 
        WHERE rs.status IN ('reservada', 'ocupada')
          AND NOW() BETWEEN rs.hora_inicio AND rs.hora_fim
    )
    AND
    -- Critério 2: NÃO pode estar ocupada por um voluntário agora
    s.idsala NOT IN (
        SELECT sala_idsala 
        FROM vol_local vl 
        WHERE vl.sala_idsala IS NOT NULL
          -- Verifica se 'agora' é maior que a entrada E (ainda não saiu OU 'agora' é menor que a saída)
          -- CAST usado para tentar forçar a comparação correta mesmo sendo VARCHAR
          AND NOW() >= CAST(vl.hora_entrada AS DATETIME)
          AND (vl.hora_saida IS NULL OR NOW() <= CAST(vl.hora_saida AS DATETIME))
    );
    
    
CREATE OR REPLACE VIEW vw_horas_voluntario_mes AS
SELECT 
    v.idvoluntario,
    v.nome,
    DATE_FORMAT(NOW(), '%Y-%m') AS mes_referencia,
    -- Calcula a diferença em minutos e divide por 60 para ter horas decimais (ex: 1h30min = 1.5)
    ROUND(SUM(TIMESTAMPDIFF(MINUTE, p.hora_entrada, p.hora_saida)) / 60, 2) AS total_horas_mes
FROM voluntario v
INNER JOIN voluntariado vd ON v.idvoluntario = vd.voluntario_idvoluntario
INNER JOIN presenca p ON vd.idvoluntariado = p.idvoluntariado
WHERE 
    p.status_presenca = 'finalizado' -- Só contabiliza turnos finalizados com hora de saída real
    AND MONTH(p.hora_entrada) = MONTH(CURDATE())
    AND YEAR(p.hora_entrada) = YEAR(CURDATE())
GROUP BY v.idvoluntario, v.nome;


CREATE OR REPLACE VIEW vw_horas_geral_mes AS
SELECT 
    DATE_FORMAT(NOW(), '%Y-%m') AS mes_referencia,
    COUNT(p.idpresenca) AS total_turnos_finalizados,
    ROUND(SUM(TIMESTAMPDIFF(MINUTE, p.hora_entrada, p.hora_saida)) / 60, 2) AS total_horas_instituicao
FROM presenca p
WHERE 
    p.status_presenca = 'finalizado'
    AND MONTH(p.hora_entrada) = MONTH(CURDATE())
    AND YEAR(p.hora_entrada) = YEAR(CURDATE());


CREATE OR REPLACE VIEW vw_localizacao_atual AS
SELECT 
    v.idvoluntario,
    v.nome AS nome_voluntario,
    v.codigo_cracha,
    -- Tenta pegar o nome do local específico (da tab vol_local). 
    -- Se não tiver, usa o nome do hospital genérico (da tab voluntariado).
    COALESCE(l.nome, vd.hospital) AS local_atual_melhor_estimativa,
    -- Se estiver numa sala específica, mostra o código ou nome dela
    COALESCE(s.codigo_sala, s.nome_sala, '-') AS sala_especifica,
    vd.atividade AS atividade_principal,
    DATE_FORMAT(p.hora_entrada, '%H:%i') AS hora_que_chegou_hoje
FROM presenca p
INNER JOIN voluntariado vd ON p.idvoluntariado = vd.idvoluntariado
INNER JOIN voluntario v ON vd.voluntario_idvoluntario = v.idvoluntario
-- JOIN para tentar achar um local específico ATUAL na tabela vol_local
LEFT JOIN vol_local vl ON v.idvoluntario = vl.voluntario_idvoluntario
    AND NOW() >= CAST(vl.hora_entrada AS DATETIME) 
    AND (vl.hora_saida IS NULL OR NOW() <= CAST(vl.hora_saida AS DATETIME))
LEFT JOIN local l ON vl.local_idlocal = l.idlocal
LEFT JOIN sala s ON vl.sala_idsala = s.idsala
WHERE p.status_presenca = 'presente';